  --bg: oklch(97.5% 0.004 240);
  --surface: oklch(100% 0 0);
  --surface-raised: oklch(99% 0.002 240);
  --fg: oklch(18% 0.02 240);
  --fg-secondary: oklch(40% 0.018 240);
  --muted: oklch(55% 0.015 240);
  --border: oklch(91% 0.006 240);
  --border-strong: oklch(84% 0.01 240);
  --accent: oklch(56% 0.14 168);
  --accent-light: oklch(92% 0.04 168);
  --accent-hover: oklch(50% 0.14 168);
  --positive: oklch(52% 0.13 155);
  --positive-bg: oklch(95% 0.03 155);
  --negative: oklch(55% 0.16 25);
  --negative-bg: oklch(95% 0.03 25);
  --warning: oklch(72% 0.14 80);
  --warning-bg: oklch(96% 0.04 80);
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;
  --radius-full: 999px;
  --shadow-sm: 0 1px 2px oklch(0% 0 0 / 0.04);
  --shadow-md: 0 4px 12px oklch(0% 0 0 / 0.06);
  --shadow-lg: 0 8px 30px oklch(0% 0 0 / 0.08);
  --font-display: 'Söhne', 'Avenir Next', -apple-system, BlinkMacSystemFont, system-ui, sans-serif;
  --font-body: -apple-system, BlinkMacSystemFont, 'SF Pro Text', system-ui, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', ui-monospace, monospace;
  --transition: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

* { box-sizing: border-box; margin: 0; padding: 0; }

html {
  font-family: var(--font-body);
  font-size: 16px;
  line-height: 1.5;
  color: var(--fg);
  background: var(--bg);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body { min-height: 100dvh; }

a { color: var(--accent); text-decoration: none; transition: color var(--transition); }
a:hover { color: var(--accent-hover); }

button {
  font-family: inherit;
  font-size: inherit;
  cursor: pointer;
  border: none;
  background: none;
  transition: all var(--transition);
}

input, select, textarea {
  font-family: inherit;
  font-size: inherit;
  color: var(--fg);
  border: 1.5px solid var(--border);
  border-radius: var(--radius-md);
  padding: 12px 16px;
  background: var(--surface);
  transition: border-color var(--transition), box-shadow var(--transition);
  width: 100%;
  outline: none;
}
input:focus, select:focus, textarea:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-light);
}
input::placeholder { color: var(--muted); }

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: var(--radius-md);
  font-weight: 600;
  font-size: 15px;
  line-height: 1;
  transition: all var(--transition);
  white-space: nowrap;
}
.btn-primary {
  background: var(--accent);
  color: white;
}
.btn-primary:hover { background: var(--accent-hover); transform: translateY(-1px); box-shadow: var(--shadow-md); }
.btn-secondary {
  background: var(--surface);
  color: var(--fg);
  border: 1.5px solid var(--border);
}
.btn-secondary:hover { border-color: var(--border-strong); background: var(--surface-raised); }
.btn-ghost {
  background: transparent;
  color: var(--fg-secondary);
  padding: 8px 12px;
}
.btn-ghost:hover { background: oklch(0% 0 0 / 0.04); color: var(--fg); }
.btn-danger { background: var(--negative); color: white; }
.btn-danger:hover { background: oklch(50% 0.16 25); }
.btn-sm { padding: 8px 16px; font-size: 13px; }
.btn-lg { padding: 16px 32px; font-size: 17px; border-radius: var(--radius-lg); }
.btn-icon {
  width: 44px; height: 44px; padding: 0;
  border-radius: var(--radius-md);
  display: grid; place-items: center;
}

.card {
  background: var(--surface);
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  padding: 24px;
}
.card-elevated { box-shadow: var(--shadow-md); border: none; }

.badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.02em;
}

