      background: var(--accent-light);
      border-radius: var(--radius-md);
      font-size: 14px;
      color: var(--accent);
      font-weight: 500;
    }
    .split-type-selector {
      display: flex;
      gap: 8px;
      margin-bottom: 16px;
    }
    .split-type-btn {
      flex: 1;
      padding: 10px;
      border: 1.5px solid var(--border);
      border-radius: var(--radius-md);
      background: var(--surface);
      font-size: 13px;
      font-weight: 600;
      color: var(--fg-secondary);
