  <title>Scan Receipt — SplitFlow</title>
  <link rel="stylesheet" href="styles.css">
  <style>
    body { background: var(--fg); color: white; min-height: 100dvh; display: flex; flex-direction: column; }
    .scan-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 16px 20px;
      position: relative;
      z-index: 10;
    }
    .scan-back {
      width: 40px; height: 40px;
      display: grid; place-items: center;
      border-radius: var(--radius-full);
      background: oklch(100% 0 0 / 0.15);
      color: white;
    }
    .scan-back:hover { background: oklch(100% 0 0 / 0.25); }
    .scan-title { font-weight: 600; font-size: 17px; }
    .scan-flash {
      width: 40px; height: 40px;
      display: grid; place-items: center;
      border-radius: var(--radius-full);
      background: oklch(100% 0 0 / 0.15);
      color: white;
    }
    .scan-flash:hover { background: oklch(100% 0 0 / 0.25); }
    .scan-flash.active { background: oklch(90% 0.06 80); color: oklch(80% 0.12 80); }
    .scan-viewfinder {
      flex: 1;
      display: flex;
      align-items: center;
      justify-content: center;
      position: relative;
      padding: 20px;
    }
    .scan-frame {
      width: 100%;
      max-width: 340px;
      aspect-ratio: 3/4;
      position: relative;
      border-radius: var(--radius-lg);
    }
    .scan-corner {
      position: absolute;
      width: 32px;
      height: 32px;
      border-color: var(--accent);
      border-style: solid;
      border-width: 0;
    }
    .scan-corner.tl { top: 0; left: 0; border-top-width: 3px; border-left-width: 3px; border-top-left-radius: var(--radius-md); }
    .scan-corner.tr { top: 0; right: 0; border-top-width: 3px; border-right-width: 3px; border-top-right-radius: var(--radius-md); }
    .scan-corner.bl { bottom: 0; left: 0; border-bottom-width: 3px; border-left-width: 3px; border-bottom-left-radius: var(--radius-md); }
    .scan-corner.br { bottom: 0; right: 0; border-bottom-width: 3px; border-right-width: 3px; border-bottom-right-radius: var(--radius-md); }
    .scan-line {
      position: absolute;
      left: 8px;
      right: 8px;
      height: 2px;
      background: var(--accent);
      box-shadow: 0 0 12px var(--accent);
      animation: scanMove 2.5s ease-in-out infinite;
      opacity: 0.8;
    }
    @keyframes scanMove {
      0%, 100% { top: 10%; }
      50% { top: 85%; }
    }
    .scan-hint {
      position: absolute;
      bottom: -40px;
      left: 0;
      right: 0;
      text-align: center;
      font-size: 14px;
      color: oklch(100% 0 0 / 0.6);
    }
    .scan-bottom {
      padding: 24px 20px calc(32px + env(safe-area-inset-bottom));
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 32px;
    }
    .scan-gallery-btn {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 6px;
      color: oklch(100% 0 0 / 0.7);
      font-size: 12px;
      font-weight: 500;
    }
    .scan-gallery-btn:hover { color: white; }
    .scan-gallery-icon {
      width: 48px; height: 48px;
      border-radius: var(--radius-md);
      background: oklch(100% 0 0 / 0.12);
      display: grid; place-items: center;
    }
    .scan-gallery-icon svg { width: 22px; height: 22px; }
    .scan-shutter {
      width: 72px; height: 72px;
      border-radius: 50%;
      border: 4px solid white;
      background: transparent;
      position: relative;
      cursor: pointer;
      transition: all var(--transition);
    }
    .scan-shutter::after {
      content: '';
      position: absolute;
      inset: 4px;
      border-radius: 50%;
      background: white;
      transition: all var(--transition);
    }
    .scan-shutter:hover::after { background: oklch(95% 0 0); }
    .scan

