    .profile-edit {
      padding: 8px 16px;
      font-size: 13px;
      font-weight: 600;
      color: var(--accent);
      border: 1.5px solid var(--accent);
      border-radius: var(--radius-md);
      transition: all var(--transition);
    }
    .profile-edit:hover { background: var(--accent-light); }
    .settings-section { margin-bottom: 32px; }
    .settings-section-title {
      font-size: 13px;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: 0.06em;
      color: var(--muted);
      margin-bottom: 12px;
      padding-left: 4px;
    }
    .settings-group {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius-lg);
      overflow: hidden;
    }
    .settings-item {
      display: flex;
      align-items: center;
      gap: 14px;
      padding: 16px;
      border-bottom: 1px solid var(--border);
      cursor: pointer;
      transition: background var(--transition);
    }
    .settings-item:last-child { border-bottom: none; }
    .settings-item:hover { background: oklch(0% 0 0 / 0.02); }
    .settings-icon {
      width: 36px; height: 36px;
      border-radius: var(--radius-md);
      display: grid; place-items: center;
      flex-shrink: 0;
    }
    .settings-icon svg { width: 18px; height: 18px; }
    .settings-item-content { flex: 1; }
    .settings-item-title { font-size: 15px; font-weight: 500; }
    .settings-item-desc { font-size: 13px; color: var(--muted); margin-top: 2px; }
    .settings-item-value {
      font-size: 14px;
      color: var(--muted);
      font-weight: 500;
    }
    .settings-chevron {
      color: var(--border-strong);
      flex-shrink: 0;
    }
    .toggle-switch {
      width: 44px;
      height: 24px;
      border-radius: 12px;
      background: var(--accent);
      position: relative;
      cursor: pointer;
      transition: background var(--transition);
      flex-shrink: 0;
    }
    .toggle-switch::after {
      content: '';
      position: absolute;
      width: 20px; height: 20px;
      border-radius: 50%;
      background: white;
      top: 2px; right: 2px;
      transition: transform var(--transition);
      box-shadow: 0 1px 3px oklch(0% 0 0 / 0.15);
    }
    .toggle-switch.off { background: var(--border-strong); }
    .toggle-switch.off::after { transform: translateX(-20px); }
    .danger-zone {
      margin-top: 40px;
      padding-top: 24px;
      border-top: 1px solid var(--border);
    }\

